import{_ as t,o,c as s,ag as a}from"./chunks/framework.BPmc_f4o.js";const b=JSON.parse('{"title":"brut test e2e","description":"","frontmatter":{},"headers":[],"relativePath":"brut-cli-commands/commands/e2e.md","filePath":"brut-cli-commands/commands/e2e.md"}'),r={name:"brut-cli-commands/commands/e2e.md"};function i(l,e,d,n,c,u){return o(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="brut-test-e2e" tabindex="-1"><code>brut test e2e</code> <a class="header-anchor" href="#brut-test-e2e" aria-label="Permalink to &quot;`brut test e2e`&quot;">​</a></h1><p>Run end-to-end (browser) tests</p><h2 id="usage" tabindex="-1">USAGE <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;USAGE&quot;">​</a></h2><pre><code>brut test e2e [options] specs_to_run...\n</code></pre><h2 id="description" tabindex="-1">DESCRIPTION <a class="header-anchor" href="#description" aria-label="Permalink to &quot;DESCRIPTION&quot;">​</a></h2><p>Runs all end-to-end tests for the app, or runs a subset of end-to-end tests using RSpec-style syntax. This will run bin/test-server first, so if that fails for some reason, no tests are run.</p><h2 id="options" tabindex="-1">OPTIONS <a class="header-anchor" href="#options" aria-label="Permalink to &quot;OPTIONS&quot;">​</a></h2><ul><li><code>--env=ENVIRONMENT</code> - Project environment, e.g. test, development, production. Default depends on the command</li><li><code>--log-level=LOG_LEVEL</code> - Log level, which should be debug, info, warn, error, or fatal. Defaults to error</li><li><code>--debug, --verbose</code> - Set log level to debug, and show log messages on stdout</li><li><code>--quiet</code> - Set log level to error</li><li><code>--log-file=FILE</code> - Path to a file where log messages are written. Defaults to $XDG_CACHE_HOME/brut/logs/brut.log</li><li><code>--[no-]log-stdout</code> - Log messages to stdout in addition to the log file</li><li><code>--help, -h</code> - Show help</li><li><code>--[no-]rebuild</code> - If true, test database is rebuilt before tests are run (default false)</li><li><code>--[no-]rebuild-after</code> - If true, test database is rebuilt after tests are run (default false)</li><li><code>--seed=SEED</code> - Set the random seed to allow duplicating a test run</li></ul><h2 id="environment-variables" tabindex="-1">ENVIRONMENT VARIABLES <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;ENVIRONMENT VARIABLES&quot;">​</a></h2><ul><li><code>E2E_RECORD_VIDEOS</code> - If set to &#39;true&#39;, videos of each test run are saved in <code>./tmp/e2e-videos</code></li><li><code>E2E_SLOW_MO</code> - If set to, will attempt to slow operations down by this many milliseconds</li><li><code>E2E_TIMEOUT_MS</code> - ms to wait for any browser activity before failing the test. And here you didn&#39;t think you&#39;d get away without using sleep in browse-based tests?</li><li><code>LOGGER_LEVEL_FOR_TESTS</code> - Can be set to debug, info, warn, error, or fatal to control logging during tests. Defaults to &#39;warn&#39; to avoid verbose test output</li><li><code>RSPEC_PROFILE_EXAMPLES</code> - If set to any value, it is converted to an int and set as RSpec&#39;s number of examples to profile. NOTE: this is used in the app&#39;s spec_helper.rb so could&#39;ve been removed</li><li><code>RSPEC_WARNINGS</code> - If set to &#39;true&#39;, configures RSpec warnings for the test run. NOTE: this is used in the app&#39;s spec_helper.rb so could&#39;ve been removed</li></ul>',10)])])}const f=t(r,[["render",i]]);export{b as __pageData,f as default};
